1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	type Item = { type: string };
11	type Step = { op: "quote"; items: Item[] };
12	type Scenario = { customer: unknown; steps: Step[] };
13	
14	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
15	
16	const sumItemPremiums = (items: Item[]): number =>
17	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
18	
19	const quote = (step: Step): { premium: number } => ({
20	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
21	});
22	
23	export const runScenario = (input: unknown): unknown => {
24	  const scenario = input as Scenario;
25	  return { results: scenario.steps.map(quote) };
26	};
